import { ListItem, MenuOverlay } from '@fs/zion-ui'
import { ContentCheck, ContentRemove } from '@fs/zion-icon'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { useChannelActions, useOpenExistingChannel } from '../../hooks/channelHooks'

export default function ChatChannelInviteMenuOverlay({ menuOverlay, channel, isHeader }) {
  const [t] = useTranslation()
  const { leaveChannel } = useChannelActions({ channel, isHeader })
  const openExistingChannel = useOpenExistingChannel()
  return (
    <MenuOverlay {...menuOverlay} inline={false}>
      <ListItem
        data-testid="accept"
        primaryText={t('chat.invite-accept.text', 'Accept')}
        startElement={<ListItem.Icon Icon={ContentCheck} />}
        onClick={() => openExistingChannel(channel)}
      />
      <ListItem
        data-testid="reject"
        startElement={<ListItem.Icon Icon={ContentRemove} />}
        primaryText={t('chat.invite-reject.text', 'Reject')}
        onClick={() => {
          channel.rejectInvite()
          leaveChannel()
          return false
        }}
      />
    </MenuOverlay>
  )
}
